import subprocess, collections
BIN='/app/reliquary'

def run(cmd):
    p=subprocess.run([BIN]+cmd.split(),capture_output=True,text=True)
    return p.returncode,p.stdout.strip()

prefix=['move north','push amber east','move south','move east','move east','move east','move north','push amber east','move east','move north','move north']
run('new')
for c in prefix:
    rc,out=run(c)
    assert rc==0,(c,rc,out)
# map for state with A open, amber at 5,5, jade at 2,1
passable={(0,3),(0,4),(0,5),(1,2),(1,3),(1,4),(1,5),(2,1),(2,2),(2,3),(2,4),(2,5),(3,1),(3,2),(3,3),(3,4),(3,5),(4,4),(5,0),(5,1),(5,2),(5,3),(5,4),(6,0),(6,1),(6,2),(6,3),(6,4),(6,5),(6,6)}
ice={(2,4),(5,2),(5,3)}
crates={(5,5),(2,1)}
start=(3,4)

def step(pos,d):
    dr,dc={'north':(-1,0),'south':(1,0),'west':(0,-1),'east':(0,1)}[d]
    r,c=pos
    nr,nc=r+dr,c+dc
    if (nr,nc) not in passable or (nr,nc) in crates:
        return None
    # enter and slide on ice
    if (nr,nc) in ice:
        r,c=nr,nc
        while True:
            tr,tc=r+dr,c+dc
            if (tr,tc) in passable and (tr,tc) not in crates:
                if (tr,tc) in ice:
                    r,c=tr,tc
                    continue
                else:
                    return (tr,tc)
            else:
                return (r,c)
    return (nr,nc)

# bfs paths
q=collections.deque([start])
prev={start:(None,None)}
while q:
    p=q.popleft()
    for d in ['north','south','west','east']:
        np=step(p,d)
        if np is not None and np not in prev:
            prev[np]=(p,d)
            q.append(np)

for pos in sorted(prev):
    # reset to prefix state
    run('new')
    for c in prefix:
        rc,out=run(c)
        assert rc==0,(c,rc,out)
    # replay path to pos
    path=[]
    cur=pos
    while prev[cur][0] is not None:
        cur,d=prev[cur]
        path.append(d)
    path.reverse()
    for d in path:
        rc,out=run('move '+d)
        assert rc==0,(pos,d,rc,out)
    beta=run('turn beta clockwise')[0]==0
    delta=run('turn delta clockwise')[0]==0
    if beta or delta:
        print(pos,'beta' if beta else '-', 'delta' if delta else '-', path)
